import WidgetKit
import SwiftUI
import AppIntents
import RealityKit

struct AvatarIntent: AppIntent {
    static var title: LocalizedStringResource = "Avatar"
    @Parameter(title: "Avatar Name") var avatarName: String
}

struct AvatarWidget: Widget {
    var body: some WidgetConfiguration {
        AppIntentConfiguration(
            kind: "AvatarWidget",
            intent: AvatarIntent.self,
            provider: .static
        ) { entry in
            RealityView { content in
                if let model = try? await ModelEntity(named: entry.avatarName) {
                    content.add(model)
                }
            }
        }
    }
}

