struct ContactListView: View {
    @State private var selected: Int?
    var body: some View {
        FocusedContent(selected: $selected) {
            ForEach(0..<10) { i in
                Text("Contact \(i)")
                    .background(selected == i ? Color.green : Color.clear)
            }
        }
    }
}

